mapper.select:
/*
	 SQL ID : SemesterDAO.selectCurrentSemester
	 설  명 : 현재 학기기수 조회
*/
SELECT * FROM (

	WHERE A.NOW_SMSTRYN = 'Y'
		AND A.ORG_ID = #{orgId}
	ORDER BY A.DGRS_YR DESC, A.DGRS_SMSTR_CHRT DESC
) A
WHERE ROWNUM <= 1

/*	설	명 : 학기기수조회 	*/

SELECT	*
FROM 	TB_LMS_SMSTR_CHRT A
		JOIN TB_LMS_SBJCT_OFRNG B ON A.SMSTR_CHRT_ID = B.SMSTR_CHRT_ID AND B.SBJCT_OFRNG_ID = #{sbjctOfrngId}
WHERE 	NOW_SMSTRYN = 'Y'
ORDER BY DGRS_YR DESC, DGRS_SMSTR_CHRT DESC

/*
	SQL ID : SemesterDAO.listSmstrChrtByDgrsYr
	설  명 : 개설된 학기기수 목록 조회(학위연도 기준)
*/


	WHERE 1=1
		AND A.ORG_ID = #{orgId}
		AND A.DGRS_YR = #{dgrsYr}
